Here's how to test `DataFetcher` with proper timeout and cancellation handling in MSTest:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ValidUrl_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler("hello world", HttpStatusCode.OK);
        var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act
        var result = await fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        // Arrange
        var handler = new FakeHandler("", HttpStatusCode.InternalServerError);
        var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert
        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync(
                "https://example.com", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(2000)]
    public async Task FetchAsync_CancellationRequested_ThrowsTaskCanceledException()
    {
        // Arrange — handler that delays forever
        var handler = new FakeHandler("", HttpStatusCode.OK, delay: Timeout.InfiniteTimeSpan);
        var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(100));

        // Act & Assert
        await Assert.ThrowsAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_CooperativeTimeout_RespectsCancellationToken()
    {
        // Arrange — slow handler, test-level token enforces timeout
        var handler = new FakeHandler("slow", HttpStatusCode.OK, delay: TimeSpan.FromSeconds(10));
        var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert — _testContext.CancellationToken fires at [Timeout]
        await Assert.ThrowsAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync(
                "https://example.com", _testContext.CancellationToken));
    }

    // Simple fake handler to avoid real HTTP calls
    private sealed class FakeHandler(
        string content, HttpStatusCode status, TimeSpan? delay = null)
        : HttpMessageHandler
    {
        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (delay is { } d)
                await Task.Delay(d, cancellationToken);

            return new HttpResponseMessage(status)
            {
                Content = new StringContent(content),
            };
        }
    }
}
```

**Key patterns shown:**

| Pattern | Why |
|---|---|
| `_testContext.CancellationToken` | Cooperates with `[Timeout]` — test aborts cleanly instead of hanging |
| `Assert.ThrowsExactlyAsync<T>` | Catches exact exception type with no `[ExpectedException]` |
| `Assert.ThrowsAsync<T>` | Used for `TaskCanceledException` (base of `OperationCanceledException` hierarchy) |
| Explicit `CancellationTokenSource` | Tests that your code respects caller-provided cancellation |
| `FakeHandler` | Avoids real network calls; controls delay/status/content |
| `sealed` class + constructor injection | MSTest best practice for performance and `TestContext` access |

The critical takeaway: **always pass `_testContext.CancellationToken`** into async calls so `[Timeout]` can actually cancel the operation rather than leaving it dangling.
